import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { pollAgentEvents } from "./agentEventPoller.js";
const SERVICE_URL = "https://test.invalid";
const API_KEY = "key-test";
const DATASET_ID = "dataset-1";
function makeEvent(createdAt, id) {
    return {
        id,
        data: { datasetId: DATASET_ID, action: "modify" },
        createdAt,
    };
}
function jsonResponse(body, init) {
    return new Response(JSON.stringify(body), {
        status: 200,
        headers: { "Content-Type": "application/json" },
        ...init,
    });
}
describe("pollAgentEvents", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    it("emits events from the response and advances the cursor across polls", async () => {
        const e1 = makeEvent("2026-05-06T00:00:01.000Z", "evt-1");
        const e2 = makeEvent("2026-05-06T00:00:02.000Z", "evt-2");
        fetchMock
            .mockResolvedValueOnce(jsonResponse({
            events: [e1, e2],
            nextSince: e2.createdAt,
        }))
            .mockResolvedValueOnce(jsonResponse({ events: [], nextSince: e2.createdAt }));
        const events = [];
        const abort = new AbortController();
        const loopPromise = pollAgentEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            datasetId: DATASET_ID,
            intervalMs: 100,
            abortSignal: abort.signal,
            onEvent: (event) => events.push(event),
        });
        // First fetch resolves immediately; let microtasks flush.
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(100);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loopPromise;
        expect(events).toEqual([e1, e2]);
        expect(fetchMock).toHaveBeenCalledTimes(2);
        const firstUrl = fetchMock.mock.calls[0][0];
        const secondUrl = fetchMock.mock.calls[1][0];
        // First call has no cursor; second call carries the advanced cursor.
        expect(firstUrl).not.toContain("since=");
        expect(secondUrl).toContain(`since=${encodeURIComponent(e2.createdAt)}`);
    });
    it("respects startCursor on the first fetch (resume mode)", async () => {
        const start = "2026-05-06T01:00:00.000Z";
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [], nextSince: start }));
        const abort = new AbortController();
        const loopPromise = pollAgentEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            datasetId: DATASET_ID,
            startCursor: start,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loopPromise;
        const firstUrl = fetchMock.mock.calls[0][0];
        expect(firstUrl).toContain(`since=${encodeURIComponent(start)}`);
    });
    it("calls onError on non-2xx responses but keeps looping", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ error: "boom" }, { status: 500 }))
            .mockResolvedValueOnce(jsonResponse({ events: [], nextSince: "" }));
        const errors = [];
        const abort = new AbortController();
        const loopPromise = pollAgentEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            datasetId: DATASET_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
            onError: (err) => errors.push(err),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(50);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loopPromise;
        expect(errors).toHaveLength(1);
        expect(errors[0].message).toMatch(/500/);
        expect(fetchMock).toHaveBeenCalledTimes(2);
    });
    it("terminates immediately when abort fires before the first fetch", async () => {
        const abort = new AbortController();
        abort.abort();
        const loopPromise = pollAgentEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            datasetId: DATASET_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await loopPromise;
        expect(fetchMock).not.toHaveBeenCalled();
    });
    it("sends the API key as a Bearer Authorization header", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [], nextSince: "" }));
        const abort = new AbortController();
        const loopPromise = pollAgentEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            datasetId: DATASET_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loopPromise;
        const init = fetchMock.mock.calls[0][1];
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
    });
});
